 1→import { useEffect, useRef } from 'react';
 2→import { createPortal } from 'react-dom';
 3→import { motion, AnimatePresence } from 'framer-motion';
 4→import { handleImageFallback } from '../../utils/handleImageFallback';
 5→import './mentionDropdown.css';
 6→
 7→const MentionDropdown = ({ isOpen, results, selectedIndex, onSelect, onHover, position, onClose }) => {
 8→    const dropdownRef = useRef(null);
 9→
10→    useEffect(() => {
11→        if (!isOpen) return;
12→
13→        const handleClickOutside = (e) => {
14→            if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
15→                onClose();
16→            }
17→        };
18→
19→        document.addEventListener('mousedown', handleClickOutside);
20→        return () => document.removeEventListener('mousedown', handleClickOutside);
21→    }, [isOpen, onClose]);
22→
23→    if (!isOpen || results.length === 0) return null;
24→
25→    return createPortal(
26→        <AnimatePresence>
27→            <motion.div
28→                ref={dropdownRef}
29→                className="mention-dropdown"
30→                style={{
31→                    position: 'fixed',
32→                    top: position.top,
33→                    left: position.left,
34→                    width: position.width ? Math.min(position.width, 300) : 260,
35→                    zIndex: 99999,
36→                }}
37→                initial={{ opacity: 0, y: -4 }}
38→                animate={{ opacity: 1, y: 0 }}
39→                exit={{ opacity: 0, y: -4 }}
40→                transition={{ duration: 0.12 }}
41→            >
42→                {results.map((user, index) => (
43→                    <div
44→                        key={user.id}
45→                        className={`mention-dropdown-item ${index === selectedIndex ? 'mention-dropdown-item--active' : ''}`}
46→                        onMouseEnter={() => onHover(index)}
47→                        onMouseDown={(e) => {
48→                            e.preventDefault();
49→                            onSelect(user);
50→                        }}
51→                    >
52→                        <img
53→                            className="mention-dropdown-avatar"
54→                            src={user.image_url || '/assets/profile.jpg'}
55→                            alt={user.name}
56→                            onError={handleImageFallback}
57→                        />
58→                        <div className="mention-dropdown-info">
59→                            <span className="mention-dropdown-name">{user.name}</span>
60→                            {user.username && (
61→                                <span className="mention-dropdown-username">@{user.username}</span>
62→                            )}
63→                        </div>
64→                    </div>
65→                ))}
66→            </motion.div>
67→        </AnimatePresence>,
68→        document.body
69→    );
70→};
71→
72→export default MentionDropdown;
