16→        const textUpToCursor = text.slice(0, cursorPos);
17→        const match = textUpToCursor.match(MENTION_REGEX);
18→
19→        if (!match || match[1].length === 0) {
20→            setIsOpen(false);
21→            setResults([]);
22→            setQuery('');
23→            setSelectedIndex(0);
24→            return;
25→        }
26→
27→        const q = match[1];
28→        setQuery(q);
29→
30→        if (debounceRef.current) clearTimeout(debounceRef.current);
31→
32→        debounceRef.current = setTimeout(async () => {
33→            try {
34→                const res = await searchUsers(q, 6);
35→                const filtered = excludeUserId
36→                    ? res?.data?.filter(u => u.id !== excludeUserId)
37→                    : res?.data;
38→                if (filtered && filtered.length > 0) {
39→                    setResults(filtered);
40→                    setSelectedIndex(0);
41→                    setIsOpen(true);
42→                } else {
43→                    setIsOpen(false);
44→                    setResults([]);
45→                }
46→            } catch {
47→                setIsOpen(false);
48→                setResults([]);
49→            }
50→        }, DEBOUNCE_MS);
51→
52→        return () => {
53→            if (debounceRef.current) clearTimeout(debounceRef.current);
54→        };
55→    }, [text, cursorPos]);
56→
57→    const close = useCallback(() => {
58→        setIsOpen(false);
59→        setResults([]);
60→        setSelectedIndex(0);
61→    }, []);
62→
63→    const moveUp = useCallback(() => {
64→        setSelectedIndex((prev) => (prev > 0 ? prev - 1 : results.length - 1));
65→    }, [results.length]);
66→
67→    const moveDown = useCallback(() => {
68→        setSelectedIndex((prev) => (prev < results.length - 1 ? prev + 1 : 0));
69→    }, [results.length]);
70→
71→    return {
72→        results,
73→        selectedIndex,
74→        setSelectedIndex,
75→        isOpen,
76→        query,
77→        close,
78→        moveUp,
79→        moveDown,
80→    };
81→};
