 10→const MENTION_REGEX = /@([\w-]*)$/;
 11→const DEBOUNCE_MS = 200;
 12→
 13→export default function MentionPlugin() {
 14→    const [editor] = useLexicalComposerContext();
 15→    const { session } = useAuth();
 16→    const [query, setQuery] = useState(null);
 17→    const [results, setResults] = useState([]);
 18→    const [selectedIndex, setSelectedIndex] = useState(0);
 19→    const [menuPosition, setMenuPosition] = useState(null);
 20→    const debounceRef = useRef(null);
 21→    const menuRef = useRef(null);
 22→    const triggerOffsetRef = useRef(null);
 23→
 24→    const isOpen = query !== null && menuPosition !== null;
 25→
 26→    const closeMenu = useCallback(() => {
 27→        setQuery(null);
 28→        setResults([]);
 29→        setSelectedIndex(0);
 30→        setMenuPosition(null);
 31→        triggerOffsetRef.current = null;
 32→    }, []);
 33→
 34→    const insertMention = useCallback((user) => {
 35→        editor.update(() => {
 36→            const selection = $getSelection();
 37→            if (!$isRangeSelection(selection)) return;
 38→
 39→            const anchor = selection.anchor;
 40→            const anchorNode = anchor.getNode();
 41→            const textContent = anchorNode.getTextContent();
 42→
 43→            // Find the @ trigger position
 44→            const matchUpToCursor = textContent.substring(0, anchor.offset);
 45→            const match = matchUpToCursor.match(MENTION_REGEX);
 46→            if (!match) return;
 47→
 48→            const mentionStart = match.index;
 49→            const mentionEnd = anchor.offset;
 50→
 51→            // Split the text node and replace the @query with MentionNode
 52→            if (mentionStart > 0) {
 53→                const [before] = anchorNode.splitText(mentionStart, mentionEnd);
 54→                const mentionNode = $createMentionNode(user.name, user.id, user.username);
 55→                const afterNode = before.getNextSibling();
 56→                if (afterNode) {
 57→                    afterNode.replace(mentionNode);
 58→                }
 59→                // Add a space after
 60→                const spaceNode = $createTextNode(' ');
 61→                mentionNode.insertAfter(spaceNode);
 62→                spaceNode.select();
 63→            } else {
 64→                const [, rest] = anchorNode.splitText(mentionEnd);
 65→                const mentionNode = $createMentionNode(user.name, user.id, user.username);
 66→                anchorNode.replace(mentionNode);
 67→                const spaceNode = $createTextNode(' ');
 68→                mentionNode.insertAfter(spaceNode);
 69→                if (rest) {
 70→                    spaceNode.insertAfter(rest);
 71→                }
 72→                spaceNode.select();
 73→            }
 74→        });
 75→        closeMenu();
 76→    }, [editor, closeMenu]);
 77→
 78→    // Listen for text changes to detect @query
 79→    useEffect(() => {
 80→        return editor.registerUpdateListener(({ editorState }) => {
 81→            editorState.read(() => {
 82→                const selection = $getSelection();
 83→                if (!$isRangeSelection(selection) || !selection.isCollapsed()) {
 84→                    closeMenu();
 85→                    return;
 86→                }
 87→
 88→                const anchor = selection.anchor;
 89→                const anchorNode = anchor.getNode();
 90→                const textContent = anchorNode.getTextContent();
 91→                const textUpToCursor = textContent.substring(0, anchor.offset);
 92→
 93→                const match = textUpToCursor.match(MENTION_REGEX);
 94→                if (!match) {
 95→                    closeMenu();
 96→                    return;
 97→                }
 98→
 99→                const mentionQuery = match[1];
100→                setQuery(mentionQuery);
101→                triggerOffsetRef.current = match.index;
102→
103→                // Calculate position from DOM selection
104→                const nativeSelection = window.getSelection();
105→                if (nativeSelection && nativeSelection.rangeCount > 0) {
106→                    const range = nativeSelection.getRangeAt(0);
107→                    const rect = range.getBoundingClientRect();
108→                    setMenuPosition({
109→                        top: rect.bottom + 4,
110→                        left: rect.left,
111→                    });
112→                }
113→            });
114→        });
115→    }, [editor, closeMenu]);
116→
117→    // Fetch results when query changes
118→    useEffect(() => {
119→        if (query === null) return;
120→
121→        if (debounceRef.current) {
122→            clearTimeout(debounceRef.current);
123→        }
124→
125→        debounceRef.current = setTimeout(async () => {
126→            if (!session?.access_token) return;
127→            try {
128→                const response = await searchFollowingUsers(session.access_token, query, 8);
129→                setResults(response?.data || []);
130→                setSelectedIndex(0);
131→            } catch (err) {
132→                console.error('mention search error:', err);
133→                setResults([]);
134→            }
135→        }, DEBOUNCE_MS);
136→
137→        return () => {
138→            if (debounceRef.current) {
139→                clearTimeout(debounceRef.current);
140→            }
141→        };
142→    }, [query, session?.access_token]);
143→
144→    // Keyboard navigation
145→    useEffect(() => {
146→        if (!isOpen) return;
147→
148→        const handleKeyDown = (e) => {
149→            if (e.key === 'ArrowDown') {
150→                e.preventDefault();
151→                setSelectedIndex((prev) => (prev + 1) % Math.max(results.length, 1));
152→            } else if (e.key === 'ArrowUp') {
153→                e.preventDefault();
154→                setSelectedIndex((prev) => (prev - 1 + results.length) % Math.max(results.length, 1));
155→            } else if ((e.key === 'Enter' || e.key === 'Tab') && results.length > 0) {
156→                e.preventDefault();
157→                insertMention(results[selectedIndex]);
158→            } else if (e.key === 'Escape') {
159→                e.preventDefault();
160→                closeMenu();
161→            }
162→        };
163→
164→        document.addEventListener('keydown', handleKeyDown, true);
165→        return () => document.removeEventListener('keydown', handleKeyDown, true);
166→    }, [isOpen, results, selectedIndex, insertMention, closeMenu]);
167→
168→    if (!isOpen || results.length === 0) return null;
169→
170→    return createPortal(
171→        <div
172→            ref={menuRef}
173→            className="mention-dropdown"
174→            style={{ top: menuPosition.top, left: menuPosition.left }}
175→        >
176→            {results.map((user, index) => (
177→                <div
178→                    key={user.id}
179→                    className={`mention-dropdown-item${index === selectedIndex ? ' mention-dropdown-item--selected' : ''}`}
180→                    onMouseDown={(e) => {
181→                        e.preventDefault();
182→                        insertMention(user);
183→                    }}
184→                    onMouseEnter={() => setSelectedIndex(index)}
185→                >
186→                    <img
187→                        className="mention-dropdown-avatar"
188→                        src={user.image_url || '/assets/profile.jpg'}
189→                        alt=""
190→                        onError={handleImageFallback}
191→                    />
192→                    <div className="mention-dropdown-info">
193→                        <span className="mention-dropdown-name">{user.name}</span>
194→                        {user.username && (
195→                            <span className="mention-dropdown-username">@{user.username}</span>
196→                        )}
197→                    </div>
198→                </div>
199→            ))}
200→        </div>,
201→        document.body
202→    );
203→}
